import java.util.Arrays;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

public class Main {
  public static void main(String[] args) {
    List<String> names = Arrays.asList("Ali", "Ayşe", "Bahar", "Berk", "Cem");
    Map<Character, List<String>> groupedByFirstLetter = names.stream()
                                                            .collect(Collectors.groupingBy(name -> name.charAt(0)));
    System.out.println("İlk hərfə görə qruplaşdırma: " + groupedByFirstLetter);
  }
}
// Çıxış: İlk hərfə görə qruplaşdırma: {A=[Ali, Ayşe], B=[Bahar, Berk], C=[Cem]}

import java.util.Arrays;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

public class Main {
  public static void main(String[] args) {
    List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
    Map<Boolean, List<Integer>> partitioned = numbers.stream()
                                                    .collect(Collectors.partitioningBy(n -> n % 2 == 0));
    System.out.println("Cüt və tək: " + partitioned);
  }
}
// Çıxış: Cüt və tək: {false=[1, 3, 5], true=[2, 4]}

import java.util.Arrays;
import java.util.List;
import java.util.Optional;

public class Main {
  public static void main(String[] args) {
    List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
    Optional<Integer> max = numbers.stream().max(Integer::compareTo);
    max.ifPresent(value -> System.out.println("Maksimum: " + value));
  }
}
// Çıxış: Maksimum: 5

